/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockEntity, FWFTextBlockLanguage))
    {
        this.insertUpdateTextBlockValue(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

/// <summary>
///
/// </summary>
public void postLoad()
{
    FWFTextBlockTable       textBlockTable;
    FWFTextBlockValue       textBlockValue;
    FWFTextBlockInstance    textBlockInstance;
    FWFTextBlockLanguage    textBlockLanguage;

    super();

    textBlockTable      = FWFTextBlockTable::findNameModule(this.Name, this.Module, this.CompanyId);
    textBlockLanguage   = FWFTextBlockLanguage::find(textBlockTable.RecId, this.TextBlockTable_LanguageId);
    textBlockInstance   = FWFTextBlockInstance::find(textBlockLanguage.RecId, textBlockLanguage.TableId);
    textBlockValue      = FWFTextBlockValue::find(textBlockInstance.ValueRecId);

    this.TextBlockValue_TextBlock = textBlockValue.TextBlock;
}

/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean updateEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockEntity, FWFTextBlockLanguage))
    {
        this.insertUpdateTextBlockValue(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

private void insertUpdateTextBlockValue(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    FWFTextBlockValue       textBlockValue;
    FWFTextBlockInstance    textBlockInstance;
    FWFTextBlockLanguage    textBlockLanguage;
    FWFTextBlockEntity      textBlockEntity;
    FWFTextBlockTable	    textBlockTable;
    FWFTextBlockTableParm   textBlockTableParm;

    textBlockLanguage   = _dataSourceCtx.getBuffer();
    textBlockEntity     = _entityCtx.getEntityRecord();

    textBlockTable = FWFTextBlockTable::find(textBlockEntity.RecId);
    if (!textBlockTable.SetupRefRecId)
    {
        ttsbegin;
        textBlockTableParm.initValue();
        textBlockTableParm.insert();
        textBlockTable.selectForUpdate(true);
        textBlockTable.SetupRefRecId = textBlockTableParm.RecId;
        textBlockTable.update();
        ttscommit;
    }

    textBlockInstance = FWFTextBlockInstance::find(textBlockLanguage.RecId, textBlockLanguage.TableId);
    if (! textBlockInstance)
    {
        textBlockInstance.RefRecId   = textBlockLanguage.RecId;
        textBlockInstance.RefTableId = textBlockLanguage.TableId;
        textBlockInstance.write();
    }

    textBlockValue = FWFTextBlockValue::findOrCreate(textBlockEntity.TextBlockValue_TextBlock);

    textBlockInstance.selectForUpdate(true);
    textBlockInstance.ValueRecId = textBlockValue.RecId;
    textBlockInstance.update();
}
